2287 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2288 |     function applyLocalPatch(content, ops) {
2289 |         let lines = content.split('\n');
2290 |         let logs = [];
2291 |         let success = true;
2292 | 
2293 |         if (typeof ops === 'string') {
2294 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2295 |         }
2296 | 
2297 |         ops.forEach(op => {
2298 |             if (op.action === 'comment') return;
2299 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2300 |             
2301 |             if (op.action === 'replace_block') {
2302 |                 // Strategy 1: Exact String Match (Fastest)
2303 |                 const currentStr = lines.join('\n');
2304 |                 if (currentStr.includes(op.find_block)) {
2305 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2306 |                     logs.push('Exact match applied');
2307 |                     return;
2308 |                 }
2309 | 
2310 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2311 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2312 |                 if (searchLines.length === 0) return;
2313 | 
2314 |                 let matchStart = -1;
2315 |                 let matchEnd = -1;
2316 | 
2317 |                 // Scan file lines
2318 |                 for (let i = 0; i < lines.length; i++) {
2319 |                     // If first line matches (ignoring whitespace)
2320 |                     if (lines[i].trim() === searchLines[0]) {
2321 |                         // Check subsequent lines
2322 |                         let allMatch = true;
2323 |                         let fileOffset = 0;
2324 |                         let searchOffset = 1;
2325 |                         
2326 |                         while (searchOffset < searchLines.length) {
2327 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2328 |                             const nextFile = lines[i + fileOffset + 1].trim();
2329 |                             // Skip empty lines in file if they aren't in search block
2330 |                             if (nextFile === '') {
2331 |                                 fileOffset++;
2332 |                                 continue;
2333 |                             }
2334 |                             if (nextFile !== searchLines[searchOffset]) {
2335 |                                 allMatch = false;
2336 |                                 break;
2337 |                             }
2338 |                             fileOffset++;
2339 |                             searchOffset++;
2340 |                         }
2341 | 
2342 |                         if (allMatch) {
2343 |                             matchStart = i;
2344 |                             matchEnd = i + fileOffset;
2345 |                             break;
2346 |                         }
2347 |                     }
2348 |                 }
2349 | 
2350 |                 if (matchStart !== -1) {
2351 |                     // Replace the range of lines
2352 |                     const replacement = op.replace_with.split('\n');
2353 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2354 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2355 |                 } else {
2356 |                     success = false;
2357 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2358 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2359 |                 }
2360 |             }
2361 |         });
2362 |         return { content: lines.join('\n'), success, logs };
2363 |     }
