5420 |         const MAX_RETRIES = 5;
5421 | 
5422 |         const attemptNavigation = async () => {
5423 |             const element = document.querySelector(selector);
5424 |             
5425 |             if (element) {
5426 |                 console.log("[DeepJump] Element found. Scrolling...");
5427 |                 
5428 |                 // Wait for any tab transition animations
5429 |                 await new Promise(r => setTimeout(r, 300));
