5456 |                 retryCount++;
5457 |                 showGlobalToast("أƒآƒأ‚آƒأƒآ‚أ‚آƒأƒآƒأ‚آ‚أƒآ‚أ‚آ°أƒآƒأ‚آƒأƒآ‚أ‚آ‚أƒآƒأ‚آ‚أƒآ‚أ‚آںأƒآƒأ‚آƒأƒآ‚أ‚آ‚أƒآƒأ‚آ‚أƒآ‚أ‚آ”أƒآƒأ‚آƒأƒآ‚أ‚آ‚أƒآƒأ‚آ‚أƒآ‚أ‚آچ Searching deeper...");
5458 |                 
5459 |                 await loadMoreFn(); 
5460 |                 await new Promise(r => setTimeout(r, 800)); // Wait for render
5461 |                 return attemptNavigation();
